/**
 * User notification preferences model.
 *
 * Controls which notifications a user receives and how they receive them.
 * Currently focused on email settings — designed to be extensible when
 * additional channels are added.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Per-category subscription flags for email notifications.
 * Each key maps to a NotificationType.
 */
export interface EmailCategoryPreferences {
  orderConfirmations: boolean;
  orderStatusUpdates: boolean;
  welcomeMessages: boolean;
  accountUpdates: boolean;
}

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  /** Master switch — when false, no emails are sent regardless of category settings */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Per-category opt-in/opt-out */
  categories: EmailCategoryPreferences;
}

/**
 * Complete user notification preferences record.
 */
export interface UserNotificationPreferences {
  /** Unique ID for this preferences record */
  id: string;
  /** The user these preferences belong to */
  userId: string;
  /** Email notification settings */
  email: EmailNotificationPreferences;
  /** When preferences were last modified */
  updatedAt: Date;
}

/**
 * Maps NotificationType to the corresponding category key in EmailCategoryPreferences.
 */
export const notificationTypeToCategory: Record<NotificationType, keyof EmailCategoryPreferences> = {
  'order-confirmation': 'orderConfirmations',
  'order-status-update': 'orderStatusUpdates',
  'welcome': 'welcomeMessages',
  'account-updated': 'accountUpdates',
};

/**
 * Default preferences for new users — all notifications enabled, immediate delivery.
 */
export function createDefaultPreferences(userId: string, id: string): UserNotificationPreferences {
  return {
    id,
    userId,
    email: {
      enabled: true,
      frequency: 'immediate',
      categories: {
        orderConfirmations: true,
        orderStatusUpdates: true,
        welcomeMessages: true,
        accountUpdates: true,
      },
    },
    updatedAt: new Date(),
  };
}

/**
 * Repository for user notification preferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Stores EmailCategoryPreferences as a JSON string in the database record.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserNotificationPreferences,
  EmailFrequency,
  EmailCategoryPreferences,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_notification_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        categories: JSON.parse(record['emailCategories'] as string) as EmailCategoryPreferences,
      },
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for notification preferences and a check method
 * used by NotificationService to gate delivery.
 *
 * When a user has no stored preferences, defaults are created automatically
 * (all notifications enabled, immediate frequency).
 */

import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  EmailNotificationPreferences,
} from '../models/user-preferences.js';
import { createDefaultPreferences, notificationTypeToCategory } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Creates defaults if none exist.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user: ${userId}`);
    const defaults = createDefaultPreferences(userId, generatePreferencesId());
    return this.repository.save(defaults);
  }

  /**
   * Update email notification preferences for a user.
   * Merges the provided updates with existing preferences.
   */
  updateEmailPreferences(
    userId: string,
    updates: Partial<EmailNotificationPreferences>,
  ): UserNotificationPreferences {
    const current = this.getPreferences(userId);
    const updatedEmail = { ...current.email };

    if (updates.enabled !== undefined) {
      updatedEmail.enabled = updates.enabled;
    }
    if (updates.frequency !== undefined) {
      updatedEmail.frequency = updates.frequency;
    }
    if (updates.categories !== undefined) {
      updatedEmail.categories = { ...updatedEmail.categories, ...updates.categories };
    }

    return this.repository.update(current.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification should be sent to a user.
   * Returns true if the notification is allowed by the user's preferences.
   */
  isNotificationEnabled(
    userId: string,
    type: NotificationType,
    channel: NotificationChannel,
  ): boolean {
    const prefs = this.getPreferences(userId);

    if (channel === 'email') {
      if (!prefs.email.enabled) {
        this.logger.info(`Email notifications disabled for user: ${userId}`);
        return false;
      }

      const categoryKey = notificationTypeToCategory[type];
      if (!prefs.email.categories[categoryKey]) {
        this.logger.info(
          `Category "${categoryKey}" disabled for user: ${userId}`,
        );
        return false;
      }

      return true;
    }

    // For channels without preference support yet, allow by default
    return true;
  }
}

